import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,t as a}from"./chunks/template-generator-advanced.CleIDHrl.js";import{n as o,t as s}from"./chunks/gradle-prompt.DgUqZl-T.js";const c=JSON.parse(`{"title":"Створення проєкту","description":"Покрокова інструкція по створенню нового мод-проєкту за допомогою генератора шаблонів модів Fabric.","frontmatter":{"title":"Створення проєкту","description":"Покрокова інструкція по створенню нового мод-проєкту за допомогою генератора шаблонів модів Fabric.","authors":["Cactooz","IMB11","radstevee"],"files":[]},"headers":[],"relativePath":"uk_ua/1.21.4/develop/getting-started/creating-a-project.md","filePath":"versions/1.21.4/translated/uk_ua/develop/getting-started/creating-a-project.md","lastUpdated":1760721669000}`);var l={name:`uk_ua/1.21.4/develop/getting-started/creating-a-project.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Створення проєкту <a class="header-anchor" href="#h1" aria-label="Permalink to “Створення проєкту”">​</a></h1><p>Fabric надає простий спосіб створити новий мод-проєкт за допомогою Fabric Template Mod Generator - якщо ви хочете, ви можете вручну створити новий проєкт, використовуючи приклад сховища модів, вам слід звернутися до <a href="#manual-project-creation">створення проєкту вручну</a> розділ.</p><h2 id="generating-a-project" tabindex="-1">Генерація проєкту <a class="header-anchor" href="#generating-a-project" aria-label="Permalink to “Генерація проєкту”">​</a></h2><p>Ви можете використати <a href="https://fabricmc.net/develop/template/" target="_blank" rel="noreferrer">Fabric Template Mod Generator</a>, щоб створити новий проєкт для свого моду – вам слід заповнити обов’язкові поля, як-от назва мода, назва пакета, і версію Minecraft, для якої ви хочете розробляти.</p><p>Назва пакета повинно бути малим регістром, розділеним крапками та унікальним, щоб уникнути конфліктів з пакетами інших програмістів. Зазвичай він форматується як зворотний інтернет-домен, наприклад <code>com.example.mod-id</code>.</p><p><img src="/assets/develop/getting-started/template-generator.png" alt="Попередній перегляд генератора" loading="lazy"></p><p>Якщо ви хочете використовувати Kotlin або офіційне мапування Mojang, а не мапування Yarn, або хочете додати генератори даних, ви можете вибрати відповідні параметри в розділі «Додаткові параметри».</p><p><img src="/assets/develop/getting-started/template-generator-advanced.png" alt="Розділ додаткових параметрів" loading="lazy"></p><p>Коли ви заповните необхідні поля, натисніть кнопку <code>Generate</code>, і генератор створить для вас новий проєкт у формі zip-файлу.</p><p>Вам слід розпакувати цей zip-файл у вибране вами місце, а потім відкрити видобуту теку в IntelliJ IDEA:</p><p><img src="/assets/develop/getting-started/open-project.png" alt="Відкрити вікно проєкту" loading="lazy"></p><h2 id="importing-the-project" tabindex="-1">Імпортування проєктів <a class="header-anchor" href="#importing-the-project" aria-label="Permalink to “Імпортування проєктів”">​</a></h2><p>Коли ви відкриєте проєкт в IntelliJ IDEA, IDE має автоматично завантажити налаштування Gradle проєкту та виконати необхідні завдання налаштування.</p><p>Якщо ви отримали сповіщення про сценарій збірки Gradle, вам слід натиснути кнопку <code>Import Gradle Project</code>:</p><p><img src="/assets/develop/getting-started/gradle-prompt.png" alt="Gradle Prompt" loading="lazy"></p><p>Після імпортування проєкту ви побачите файли проєкту в провіднику проєктів і зможете розпочати розробку мода.</p><h2 id="manual-project-creation" tabindex="-1">Створення проєкту власноруч <a class="header-anchor" href="#manual-project-creation" aria-label="Permalink to “Створення проєкту власноруч”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Вам знадобиться встановити <a href="https://git-scm.com/" target="_blank" rel="noreferrer">Git</a>, щоб клонувати приклад сховища модів.</p></div><p>Якщо ви не можете використовувати генератор шаблонів Fabric Mod Generator, ви можете створити новий проєкт вручну, виконавши ці дії.</p><p>По-перше, клонуйте приклад репозиторію модів за допомогою Git:</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> клон</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/FabricMC/fabric-example-mod/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-mod-project</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Це призведе до клонування репозиторію в нову теку під назвою <code>my-mod-project</code>.</p><p>You should then delete the <code>.git</code> folder from the cloned repository, and then open the project in IntelliJ IDEA. Якщо тека <code>.git</code> не показується, вам слід увімкнути показ прихованих файлів у вашому файловому менеджері.</p><p>Коли ви відкриєте проєкт в IntelliJ IDEA, він має автоматично завантажити налаштування Gradle проєкту та виконати необхідні завдання налаштування.</p><p>Знову ж таки, як згадувалося раніше, якщо ви отримуєте сповіщення про сценарій збірки Gradle, вам слід натиснути кнопку <code>Import Gradle Project</code>.</p><h3 id="modifying-the-template" tabindex="-1">Змінення шаблону <a class="header-anchor" href="#modifying-the-template" aria-label="Permalink to “Змінення шаблону”">​</a></h3><p>Після того як проєкт буде імпортовано, ви повинні змінити деталі проєкту, щоб вони відповідали деталям вашого моду:</p><ul><li>Змініть файл <code>gradle.properties</code> проєкту, щоб змінити властивості <code>maven_group</code> і <code>archive_base_name</code> відповідно до деталей вашого моду.</li><li>Змініть файл <code>fabric.mod.json</code>, щоб змінити властивості <code>id</code>, <code>name</code> і <code>description</code> відповідно до деталей вашого моду.</li><li>Переконайтеся, що ви оновили версії Minecraft, мапування, Loader і Loom, які можна отримати через <a href="https://fabricmc.net/develop/" target="_blank" rel="noreferrer">https://fabricmc.net/develop/</a>, аби відповідати версіям, на які ви хочете націлити.</li></ul><p>Очевидно, ви можете змінити назву пакета та основний клас мода, щоб відповідати деталям вашого мода.</p>`,29)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};